update public.lessons l set enhancements = $ench${"industryStory":"A team automated everything, including a screen that changed weekly. They spent more time fixing broken tests than testing. Knowing what *not* to automate is as important as knowing what to automate.","visualAid":{"type":"matrix","title":"Automation candidates","colLabels":["Changes often","Stable"],"rowLabels":["Run often","Run rarely"],"cells":[[{"label":"Risky — high upkeep","level":"high"},{"label":"Automate — best ROI","level":"low"}],[{"label":"Avoid","level":"critical"},{"label":"Maybe later","level":"medium"}]],"caption":"Best candidates: run often + stable (e.g. regression, smoke)."},"davidTip":"Automate the repetitive, stable, high-value checks — and leave exploratory and fast-changing work to humans. The decision of *what* to automate is a judgement call I expect a tester to be able to explain, not just \"automate everything\".","miniChallenge":"From a feature you know, pick three checks worth automating and two that are not — with a one-line reason each.","modelAnswer":"## Example — login\nAutomate: valid login (runs every release, stable), locked-account rule, password validation. Do not automate (yet): a brand-new redesigned screen (changes weekly), a one-off data migration check.","resourcePreview":{"name":"Test Strategy Template","purpose":"Frames decisions like what to automate and at which layer.","whenToUse":"Use it to justify your automation scope for the assignment.","formats":["DOCX","PDF"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 8 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A suite of 300 slow UI tests took two hours and was always flaky. Most of what they checked could have been unit or API tests running in seconds. The automation pyramid is the model that prevents this top-heavy mess.","visualAid":{"type":"comparison","title":"The automation pyramid","headers":["Layer","Amount","Speed / stability"],"rows":[["Unit","Most","Fastest, most stable"],["Integration / API","Some","Fast, stable"],["UI / End-to-end","Fewest","Slow, more brittle"]]},"davidTip":"When a check can be written at a lower layer, write it there. UI tests are the most expensive to build and maintain — spend them only on critical journeys that truly need the browser.","miniChallenge":"Take five checks for a feature and assign each to a pyramid layer (unit, API, UI), with a one-line justification.","modelAnswer":"## Example — discount feature\n- Discount maths correct → unit\n- API applies discount to order total → API\n- Invalid code rejected → API\n- End-to-end \"apply code at checkout\" happy path → UI\n- Field validation message → unit/UI (cheapest that proves it)"}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 8 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A junior copied an automated test they did not understand; when it failed, they could not fix it. Understanding the anatomy — setup, action, assertion — is what lets you read, write and debug automated tests with confidence.","visualAid":{"type":"flow","title":"Anatomy of a test (Arrange–Act–Assert)","steps":[{"label":"Arrange","detail":"set up state / navigate"},{"label":"Act","detail":"perform the user action"},{"label":"Assert","detail":"verify the expected outcome"}]},"davidTip":"Every good automated test reads as Arrange–Act–Assert and checks one behaviour. If you can describe a test in one sentence, it is well-scoped; if your sentence needs an \"and\", split it.","miniChallenge":"In plain English (or pseudocode), write the Arrange/Act/Assert for \"a valid login lands on the dashboard\".","modelAnswer":"## Example\nArrange: a registered user exists; go to /login.\nAct: enter valid email + password; click Sign in.\nAssert: the URL is /dashboard and the user's name shows in the header."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 8 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"An automation suite broke every time designers tweaked CSS, because tests targeted fragile selectors like div > div:nth-child(3). Switching to user-facing locators made the suite survive redesigns. Locators are where automation stability is won or lost.","badGood":{"label":"a locator","bad":"page.locator('div.container > div:nth-child(3) > button.btn-primary')","good":"page.getByRole('button', { name: 'Sign in' })"},"davidTip":"Locate elements the way a user describes them — \"the Sign in button\" → getByRole('button', { name: 'Sign in' }). User-facing locators survive markup changes and double as accessibility checks. Brittle CSS chains are the number-one cause of flaky UI tests.","miniChallenge":"Rewrite two brittle locators (a deep CSS chain and an index-based one) as user-facing locators.","modelAnswer":"## Example\n- '.list li:nth-child(2) a' → getByRole('link', { name: 'Settings' })\n- '#root > div > form > input' → getByLabel('Email address')"}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 8 and l.lesson_number = 4;

update public.lessons l set enhancements = $ench${"industryStory":"A test slept for 5 seconds \"to be safe\" before every check. The suite was painfully slow and still flaky under load. Modern assertions wait intelligently — fixed sleeps are the worst of both worlds.","badGood":{"label":"waiting in a test","bad":"wait 3 seconds, then check the toast is visible","good":"assert the toast is visible (the assertion auto-waits until it appears or times out)"},"davidTip":"Every fixed sleep is either too long (slow suite) or too short (flaky test). Use web-first assertions that retry until the condition is met, and wait on real events (a URL change, a response) rather than arbitrary time.","miniChallenge":"Describe how you would replace a \"sleep then click\" with a reliable wait, and one event you might wait on instead of a fixed time.","modelAnswer":"## Example\nInstead of sleeping then clicking Submit, assert the button is enabled (which auto-waits) then click. For navigation, wait on the URL changing to /dashboard rather than guessing a delay.","portfolioBuilder":"Even a small, reliable automated test or two — using good locators and assertions — makes a strong portfolio addition that shows you understand automation, not just manual testing."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 8 and l.lesson_number = 5;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, your reasoning matters more than code volume. A clear \"automate / do not automate\" decision with justification shows the judgement employers actually want from someone moving into automation.","miniChallenge":"Before submitting, sanity-check each \"automate\" decision against frequency, stability and value — and note why each \"do not automate\" item was excluded.","managersReview":{"intro":"If I reviewed this automation assignment as a QA lead, I would look for:","strengths":["Sensible automate/not-automate decisions with reasons","Awareness of the pyramid (right layer)","Robust locators and reliable assertions"],"gaps":["\"Automate everything\" with no reasoning","Everything pushed to UI tests","Brittle locators and fixed sleeps"],"improvements":["Justify each decision by frequency/stability/value","Move checks to the lowest sensible layer","Use user-facing locators and auto-waiting assertions"]}}$ench$::jsonb
