update public.lessons l set enhancements = $ench${"industryStory":"A tester used to spend an hour drafting test cases for a story. With AI they draft in ten minutes, then spend the rest reviewing, adding edge cases and assessing risk — better coverage in the same hour. AI did not replace the tester; it amplified them.","visualAid":{"type":"comparison","title":"What AI does and does not do in QA","headers":["AI is good at","AI is NOT a substitute for"],"rows":[["Drafting test cases and data fast","Your testing judgement and risk thinking"],["Explaining errors and code","Knowing your product and users"],["Spotting gaps and ideas","Accountability for quality"]]},"davidTip":"Frame AI as a productivity multiplier, not a replacement. In real QA teams, the testers who use AI well do the routine faster and spend the saved time on high-value thinking — and they always review what AI produces.","miniChallenge":"List three QA tasks AI could speed up for you, and one decision that must stay with you as the tester.","modelAnswer":"## Example\nAI speeds up: drafting test cases, generating test data, explaining an unfamiliar error. Stays with me: deciding what to test based on risk — AI can suggest, but I own the coverage and the quality call."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 9 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A tester typed \"write tests for login\" and got generic, shallow output. A colleague gave role, context, the rules, and a format — and got usable, specific cases. The difference was the prompt, not the tool.","badGood":{"label":"a QA prompt","bad":"\"Write test cases for login.\"","good":"\"Act as a senior QA engineer. For a login with email + password, generate positive, negative and boundary test cases as a table (ID, scenario, steps, expected result). Do not invent fields; ask me if context is missing.\""},"davidTip":"A great prompt is just clear thinking written down: role + context + task + format + constraints. If you can brief a junior tester to do the task, you can prompt AI to draft it. Vague prompts get vague output.","miniChallenge":"Take a weak prompt (\"test the checkout\") and rewrite it with role, context, task, format and a constraint.","modelAnswer":"## Example\n\"Act as a QA analyst. For a checkout that accepts a discount code and one payment method, write test cases covering happy path, invalid/expired codes and a failed payment, as a table with steps and expected results. Do not assume fields that I have not described.\""}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 9 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"AI generated 20 test cases in seconds — but two referenced a \"loyalty points\" feature that did not exist, and it missed the password boundary cases. The value came from the tester reviewing, cutting the hallucination and adding what was missing.","visualAid":{"type":"flow","title":"Generate then review","steps":[{"label":"Prompt","detail":"role + context + constraints"},{"label":"Generate","detail":"AI drafts cases"},{"label":"Review","detail":"cut hallucinations; add gaps"},{"label":"Own","detail":"you stand behind the set"}]},"davidTip":"Treat AI output like work from a junior — helpful, but you verify it. Use your test-design techniques (equivalence, boundaries) to judge whether the generated set is actually complete, and remove anything that does not match the real product.","miniChallenge":"Generate test cases for a feature with AI, then list two issues you found and fixed (a missing case and an incorrect/invented one).","modelAnswer":"## Example\nFor a sign-up form, AI missed the password length boundaries (added them) and invented an \"SMS verification\" step the product does not have (removed it). Reviewing turned a rough draft into a trustworthy set."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 9 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"A tester pasted a messy bug description into AI and asked it to tighten the wording and structure. The result was clearer and faster to action — but the tester still verified every technical detail, because AI cannot know the real environment.","davidTip":"AI is great for polishing the *words* of a bug report — clarity, structure, completeness — but the technical facts stay your responsibility. Let it improve readability; never let it invent steps, environments or severity. And never paste sensitive or production data into a public tool.","miniChallenge":"Write a rough bug report, ask AI to improve its clarity and structure, then list one improvement you accepted and one suggestion you rejected because it was wrong.","modelAnswer":"## Example\nAccepted: AI restructured my steps into numbered, minimal repro steps and sharpened the title. Rejected: it guessed the severity as \"Critical\" — I set it to High based on the real business impact it could not know.","portfolioBuilder":"An \"AI-assisted testing\" example — a prompt, the output, and your review notes — is a modern, standout portfolio piece that shows you use AI responsibly and effectively."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 9 and l.lesson_number = 4;

update public.lessons l set enhancements = $ench${"industryStory":"A tester nearly pasted a real customer record into a public AI tool to \"speed things up\". Catching that habit early is essential — responsible AI use is now a professional expectation, and a single data leak can be career-defining.","visualAid":{"type":"comparison","title":"Responsible AI use","headers":["Do","Do not"],"rows":[["Use synthetic / dummy data","Paste secrets, customer or production data"],["Verify every specific against reality","Trust output as fact"],["Review and own the result","Let AI make the quality decision"]]},"davidTip":"A simple test before you send a prompt: \"would I be comfortable if this were public?\" If not, do not send it. Being able to articulate responsible AI use — data, verification, accountability — is genuinely valued in interviews now.","miniChallenge":"Write your own three-sentence \"responsible AI\" statement covering data, verification and accountability — the kind you could say in an interview.","modelAnswer":"## Example\n\"I only use approved tools and never paste real customer or production data. I treat AI output as a draft I verify against the real system. I stay accountable for the final result as if I produced it myself.\""}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
