update public.lessons l set enhancements = $ench${"industryStory":"Two candidates applied for the same junior QA role. One said \"I understand testing\". The other shared a public portfolio: test cases, a bug report, a Postman collection and an RTM. The second got the interview — because they proved it instead of claiming it.","visualAid":{"type":"comparison","title":"Claims vs evidence","headers":["","Just a claim","A portfolio"],"rows":[["\"I can write test cases\"","Unverified","Here is a structured pack"],["\"I understand defects\"","Unverified","Here is a professional bug report"],["\"I can test APIs\"","Unverified","Here is a Postman collection"]]},"davidTip":"For someone without years of experience, a portfolio is the single most persuasive thing you can show. As a hiring manager, I would rather see one real artefact than read three paragraphs of \"I am passionate about quality\".","miniChallenge":"List the artefacts you have already created across this course that could go into your portfolio.","modelAnswer":"## Example\nTest case pack (Module 2), professional bug report (Module 3), agile acceptance-criteria example (Module 4), RTM (Module 5), Postman collection (Module 6), SQL validation snippets (Module 7), AI-assisted testing example (Module 9).","portfolioBuilder":"This module assembles everything you have built into one coherent portfolio — the centrepiece you will point employers to."}$ench$::jsonb
