  and m.module_number = 10 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A candidate's portfolio had twenty files with no explanation — the reviewer could not tell what was good. A curated set of six artefacts, each with a line of context, would have made far more impact. Quality and clarity beat quantity.","visualAid":{"type":"comparison","title":"A strong QA portfolio includes","headers":["Artefact","What it proves"],"rows":[["Test plan / strategy snapshot","You plan, not just execute"],["Test case pack","You design coverage with techniques"],["Professional bug report","You communicate defects clearly"],["RTM","You think about traceability"],["API collection (Postman)","You test beyond the UI"],["Exploratory charter + notes","You test creatively"]]},"davidTip":"Six strong, well-explained pieces beat twenty unexplained ones. Curate ruthlessly, and add a two-line note to each artefact saying what it demonstrates — reviewers should never have to guess.","miniChallenge":"Choose the six artefacts you will include and write a one-line \"what this demonstrates\" note for each.","modelAnswer":"## Example\n\"Bug report — shows I can document a critical defect so a developer can fix it fast.\" \"RTM — shows I map requirements to tests and can prove coverage.\"","resourcePreview":{"name":"Final Portfolio Project Workbook","purpose":"Guides you to assemble a complete, professional QA portfolio.","whenToUse":"Use it as the checklist while building your portfolio.","formats":["DOCX","PDF"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
