update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, make your CV and LinkedIn consistent and achievement-led, with your portfolio linked from both. Proofread relentlessly — a typo on a QA application is the worst possible first impression.","miniChallenge":"Before submitting, run the \"six-second test\": can a stranger tell your role, top skills and that you have a portfolio within six seconds of seeing your CV?","managersReview":{"intro":"If I received your CV and LinkedIn as a hiring manager, I would look for:","strengths":["Sharp summary and skills up top","Achievement bullets with outcomes","Portfolio linked; consistent CV/LinkedIn"],"gaps":["Generic objective and duty bullets","No metrics or outcomes","No portfolio link; typos"],"improvements":["Lead with relevant skills","Rewrite duties as quantified achievements","Link the portfolio and proofread"]},"portfolioBuilder":"Your CV, LinkedIn and portfolio now form one consistent story. Together they are the package you take to the job market in the final module."}$ench$::jsonb
