update public.lessons l set enhancements = $ench${"industryStory":"A candidate walked into a \"QA interview\" expecting only technical questions and was thrown by a behavioural round and a test task. Knowing the typical process — and preparing for each stage — is what turns nerves into confidence.","visualAid":{"type":"timeline","title":"A typical QA interview process","steps":[{"label":"Application / screen","detail":"CV + recruiter call"},{"label":"Technical interview","detail":"testing fundamentals"},{"label":"Behavioural","detail":"teamwork, scenarios (STAR)"},{"label":"Test task","detail":"design tests / find bugs"},{"label":"Final / offer","detail":"fit + negotiation"}]},"davidTip":"Prepare for each stage deliberately — fundamentals for the technical round, STAR stories for behavioural, and a calm approach to test tasks. And always prepare two thoughtful questions to ask; candidates who do are the ones interviewers remember.","miniChallenge":"Map the stages you would expect for a junior QA role and note one way you would prepare for each.","modelAnswer":"## Example\nScreen: tight CV + a 60-second intro. Technical: revise severity/priority, test design, STLC. Behavioural: 5 STAR stories. Test task: a calm, structured approach (analyse, design, document). Final: research the company and prepare questions."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 12 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"Asked \"what's the difference between severity and priority?\", one candidate rambled; another answered in two crisp sentences with an example. Same knowledge — but clarity under pressure is what gets remembered.","visualAid":{"type":"comparison","title":"Common QA question types","headers":["Type","Example","How to answer"],"rows":[["Definitions","Severity vs priority?","Define both in a line + example"],["Process","When do you stop testing?","Risk-based, exit criteria"],["Scenario","How would you test a login?","Structured: positive/negative/edge"],["Behavioural","A defect you are proud of?","STAR"]]},"davidTip":"For any \"what's the difference between…\" question, define both terms in one line each, then give a quick example. That structure instantly sounds confident and clear — and it works for most technical QA questions.","miniChallenge":"Answer out loud, in under 30 seconds each: (1) severity vs priority, (2) when do you stop testing, (3) how would you test a text field.","modelAnswer":"## Example — \"how would you test a text field?\"\n\"I'd use equivalence partitioning and boundary analysis: valid input, empty, max length and just over, special characters, and a SQL/script injection attempt for security. I'd also check it behaves on different browsers.\""}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
