  and m.module_number = 12 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"\"Tell me about a conflict with a developer\" sank one candidate into a rambling, negative story. Another used STAR: brief situation, their action, a positive result. The structure made them sound composed and senior.","visualAid":{"type":"flow","title":"The STAR structure","steps":[{"label":"Situation","detail":"brief context"},{"label":"Task","detail":"your responsibility"},{"label":"Action","detail":"what YOU did (the core)"},{"label":"Result","detail":"the outcome, ideally measurable"}]},"badGood":{"label":"a behavioural answer","bad":"\"A developer was annoying about a bug so I just kept arguing until they fixed it.\"","good":"\"A developer pushed back on a bug (S). I needed to resolve it without friction (T). I calmly re-walked the steps with evidence and framed it around user impact (A). We agreed it was valid and fixed it, and worked well together after (R).\""},"davidTip":"Prepare 5–6 STAR stories and you can adapt them to almost any behavioural question. Spend most of the answer on the Action, say \"I\" not \"we\", and end on a concrete result. Stay positive even about conflicts and mistakes.","miniChallenge":"Write a STAR answer for \"tell me about a defect you are proud of finding\".","modelAnswer":"## Example\nS: late in a release, the checkout intermittently double-charged. T: I had to pin it down fast. A: I reproduced it, isolated it to a specific payment method, and documented it clearly with evidence. R: it was fixed before release, avoiding a customer-facing billing failure.","portfolioBuilder":"Your portfolio is a goldmine of STAR material — each artefact (a bug you found, an RTM you built) is a ready-made \"tell me about a time\" story."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 12 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"Given a test task — \"find bugs in this page\" — one candidate clicked randomly; another announced a structured approach (explore, apply techniques, log clear bugs) and talked through their thinking. The structured one impressed even with fewer bugs found.","visualAid":{"type":"flow","title":"Approaching a test task","steps":[{"label":"Clarify","detail":"scope and priorities"},{"label":"Explore","detail":"understand the feature"},{"label":"Apply techniques","detail":"partitions, boundaries, negative"},{"label":"Document","detail":"clear bugs / test cases"}]},"davidTip":"In a test task, your *approach* is being assessed as much as your findings. Narrate your thinking, apply recognisable techniques, and write up anything you find clearly. A structured tester who finds five real issues beats a random clicker who finds six.","miniChallenge":"For a sample task (\"test this sign-up form in 20 minutes\"), write the plan you would follow before touching it.","modelAnswer":"## Example\n\"First clarify scope. Then apply equivalence/boundary analysis to each field, test negative cases (empty, invalid email, weak password), check validation messages, and try one security input. I'd log each issue as a clear, reproducible bug and note coverage at the end.\""}$ench$::jsonb
